create table dirkspzm32.ts_schedule_cfg (
    sid                     varchar2(2 char) not null enable,
    firma_nr                number(6, 0) not null enable,
    schedule_cfg_id         number(*, 0) not null enable,
    p_schedule_cfg_id       number(*, 0),
    event_type              number(*, 5) not null enable,
    start_time              date not null enable,
    finish_time             date not null enable,
    all_day                 varchar2(1 char) default 'F',
    enabled                 varchar2(1 char) default 'F',
    reminder_enabled        varchar2(1 char) default 'F',
    reminder_message        varchar2(255 char),
    reminder_minutes        number(*, 12),
    reminder_date           date,
    schedule_name           varchar2(50 char) not null enable,
    schedule_caption        varchar2(255 char),
    schedule_description    varchar2(255 char),
    recurrence_index        number(*, 5) default - 1 not null enable,
    recurr_count            number(*, 5),
    recurr_day_number       number(*, 12),
    recurr_day_type         number(*, 12),
    recurr_finish           date,
    recurr_occur_days       varchar2(20 char),
    recurr_periodicity      number(*, 5),
    recurr_type             number(*, 5),
    recurr_start_day        date,
    recurr_year_periodicity number(*, 12),
    sched_res_id            number(*, 0) default 1 not null enable,
    location                varchar2(100 char),
    time_line_state         number(*, 0) not null enable,
    last_actual_start       date,
    last_actual_finish      date,
    ts_job_name             varchar2(50 char),
    next_start              date,
    dx_options              number(*, 5),
    dx_recurrence_info      blob,
    dx_item_color           number(*, 12)
);

alter table dirkspzm32.ts_schedule_cfg
    add constraint pk_ts_schedule_cfg
        primary key ( sid,
                      firma_nr,
                      schedule_cfg_id )
            using index enable;


